// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MAX_N 1000000
#define EPS 1e-6

int main() {
    int N;
    scanf("%d", &N);
    double dp[MAX_N * 2 + 1];
    for (int i = 0; i <= MAX_N * 2; i++) {
        dp[i] = 0;
    }
    dp[0] = 0;
    dp[N * 2] = 0;
    for (int i = N * 2 - 1; i >= 1; i--) {
        dp[i] = 1 + 0.5 * dp[i + 1] + 0.5 * dp[i - 1];
    }
    printf("%.6f\n", dp[N]);
    return 0;
}

